VALUES ('От боли в горле', 'Russia', 'Россия', 'Стрепсилс', 'Амилметакрезол, деквалиния хлорид',
        'Лекарственный препарат, содержит антисептик и анестетик, который помогает снять боль и устранить воспаление в горле. Стрепсилс применяется для симптоматического лечения заболеваний горла, таких как фарингит и тонзиллит.',
        'Симптоматическое лечение боли в горле при инфекционно-воспалительных заболеваниях.', 'Повышенная чувствительность к компонентам препарата.
Детский возраст до 6 лет.
Дефицит сахаразыизомальтазы, непереносимость фруктозы, глюкозо-галактозная мальабсорбция.', 'Взрослые и дети старше 6 лет рассасывать по одной таблетке каждые 2-3 часа. Не принимать более 8 таблеток в течение 24 часов. Не превышайте указанную дозу.
Продолжительность курса лечения - не более 3 дней.', TRUE, TRUE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
