                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Обработка ран', 'Russia', 'Россия', 'Пантенол', 'Декспантенол',
        'Лекарственный препарат. Ожоги, ссадины, пролежни, для ускорения заживления ран, фурункулез, трофические язвы, атопический дерматит, пеленочный дерматит, опрелости, сухая кожа', 'Нарушения целостности кожного покрова, вызванные механическими, химическими, температурными факторами или после хирургических вмешательств
- ожоги различного происхождения (в т.ч. солнечные);
- царапины, ссадины, раны, пролежни;
- плохо заживающие асептические послеоперационные раны;
- дерматиты, фурункулы, трофические язвы нижних конечностей;
- лечение и профилактика трещин и воспаления сосков молочной железы во время лактации;
- уход за детьми профилактика и лечение опрелостей у грудных детей, активизация процесса заживления кожи при мелких повреждениях, пеленочный дерматит;
- для обработки и защиты сухой кожи;
- лечение и профилактика последствий неблагоприятного воздействия на кожу факторов внешней среды (холода, ветра, влажности).',
        'Повышенная чувствительность к компонентам препарата.', 'Наружно. Мазь наносят тонким слоем на пораженный участок, слегка втирая, 2-4 раза в сутки (при необходимости чаще). В случае нанесения на инфицированную поверхность кожи, ее следует предварительно обработать любым антисептиком. Кормящим матерям необходимо смазывать поверхность соска мазью после каждого кормления грудью.
Грудным детям наносят мазь после каждой смены белья или водной процедуры. Длительность применения препарата зависит от индивидуальных особенностей течения заболевания у пациента и определяется достигнутым терапевтическим эффектом и переносимостью препарата.
Если после лечения улучшения не наступает или появляются новые симптомы, необходимо проконсультироваться с врачом.
Применяйте препарат только согласно тому способу применения и в тех дозах, которые указаны в инструкции. В случае необходимости, пожалуйста, проконсультируйтесь с врачом перед применением лекарственного препарата.',
        TRUE, TRUE, TRUE, TRUE, TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
