VALUES ('От отравления', 'Russia', 'Россия', 'Полисорб', 'Кремний диоксид коллоидный', 'Лекарственный препарат. Энтеросорбент
широкого спектра действия', '- острые и хронические интоксикации различного происхождения у взрослых и детей.
- острые кишечные инфекции любого генеза, включая пищевые токсикоинфекции, а также диарейный синдром неинфекционного происхождения, дисбактериоз (в составе комплексной терапии).
- гнойно-септические заболевания, сопровождающиеся выраженной интоксикацией.
- острые отравления сильнодействующим и ядовитыми веществами, в том числе лекарственными препаратами и алкоголем, алкалоидами, солями тяжелых металлов и др.
- пищевая и лекарственная аллергия.
- вирусный гепатит и другие желтухи (гипербилирубинемия).
- хроническая почечная недостаточность (гиперазотемия).
- жителям экологически неблагоприятных регионов и работникам вредных производств, с целью профилактики.', 'Язвенная болезнь желудка и 12-ти перстной кишки в фазе обострения.
Кровотечения из желудочно-кишечного тракта.
Атония кишечника.Индивидуальная непереносимость препарата.',
        'Доза и схема применения устанавливаются индивидуально, в зависимости от показаний, возраста и массы тела пациента.',
        TRUE, TRUE, TRUE, TRUE, TRUE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От отравления', 'Russia', 'Россия', 'Энтеросгель', 'Полиметилсилоксана полигидрат',
        'Лекарственный препарат. Гелеобразный энтеросорбент, созданный, чтобы адсорбировать, быстро и безопасно вывести из организма токсины, аллергены, вирусы, патогены и другие вредные вещества при отравлениях, аллергии, проблемах с ЖКТ, кожей и во многих других ситуациях.', 'У взрослых и детей в качестве детоксикационного средства
- острые и хронические интоксикации различного происхождения;
- острые отравления сильнодействующими и ядовитыми веществами, в том числе лекарственными препаратами и алкоголем, алкалоидами, солями тяжёлых металлов;
- острые кишечные инфекции любого генеза в составе комплексной терапии (токсикоинфекции, сальмонеллёз, дизентерия, диарейный синдром неинфекционного происхождения, дисбактериоз);
- гнойно-септические заболевания, сопровождающиеся выраженной интоксикацией, в составе комплексной терапии;
- пищевая и лекарственная аллергия;
- гипербилирубинемия (вирусные гепатиты) и гиперазотемия (хроническая почечная недостаточность);
- с целью профилактики хронических интоксикаций работникам вредных производств (профессиональные интоксикации химическими агентами политропного действия, ксенобиотиками, инкорпорированными радионуклидами, соединениями свинца, ртути, мышьяка, нефтепродуктами, органическими растворителями, окислами азота, углерода, фторидами, солями тяжёлых металлов).', 'Для пасты стандартной Индивидуальная непереносимость препарата, атония кишечника.
Для пасты сладкой Детский возраст до 1 года, индивидуальная непереносимость препарата, атония кишечника, непереносимость сульфаниламидных препаратов.', 'Энтеросгель пасту принимают внутрь за 1-2 часа до или после еды или приёма других лекарств, запивая водой.
Необходимое для приема количество препарата рекомендуется размешать в стакане в тройном объеме воды комнатной температуры или принимать внутрь, запивая водой. Дозировка для взрослых 15 г - 22,5 г (1 - 1,5 столовой ложки) 3 раза в сутки. Суточная доза 45 г - 67,5 г.
Детям в возрасте от 5 до 14 лет - 15 г (1 столовая ложка) 3 раза в сутки. Суточная доза 45 г.
Детям в возрасте до 5 лет - 7,5 г (0,5 столовой ложки) 3 раза в сутки. Суточная доза 22,5 г.
Грудным детям рекомендуется 2,5 г (0,5 чайной ложки) препарата размешать в тройном объеме грудного молока или воды и давать перед каждым кормлением (6 раз в сутки).
Для профилактики хронических интоксикаций - по 22,5 г 2 раза в день в течение 7-10 дней ежемесячно. При тяжёлых интоксикациях в течение первых трёх суток доза препарата может быть увеличена вдвое.
Продолжительность лечения при острых отравлениях 3-5 суток, а при хронических интоксикациях и аллергических состояниях 2-3 недели. Повторный курс по рекомендации врача.',
        TRUE, TRUE, TRUE, TRUE, FALSE, FALSE);
